@RestController
@RequestMapping("/api/events")
class EventProducerController {

    private final KafkaTemplate<String, String> kafkaTemplate;
    private final ObjectMapper objectMapper;

    public EventProducerController(KafkaTemplate<String, String> kafkaTemplate, 
                                  ObjectMapper objectMapper) {
        this.kafkaTemplate = kafkaTemplate;
        this.objectMapper = objectMapper;
    }

    @PostMapping("/publish")
    public EventResponse publishEvent(@RequestBody EventRequest eventRequest,
                                     @RequestHeader(value = "tracking-id", required = false) String trackingId,
                                     @RequestHeader(value = "user-id", required = false) String userId,
                                     @RequestHeader(required = false) Map<String, String> headers) {
        
        try {
            List<Header> kafkaHeaders = new ArrayList<>();
            
            if (trackingId != null && !trackingId.isEmpty()) {
                kafkaHeaders.add(new RecordHeader("tracking-id", 
                    trackingId.getBytes(StandardCharsets.UTF_8)));
            }
            
            if (userId != null && !userId.isEmpty()) {
                kafkaHeaders.add(new RecordHeader("user-id", 
                    userId.getBytes(StandardCharsets.UTF_8)));
            }
            
            if (eventRequest.getHeaders() != null) {
                for (Map.Entry<String, String> entry : eventRequest.getHeaders().entrySet()) {
                    kafkaHeaders.add(new RecordHeader(entry.getKey(), 
                        entry.getValue().getBytes(StandardCharsets.UTF_8)));
                }
            }
            
            if (eventRequest.getMetadata() != null) {
                for (Map.Entry<String, String> entry : eventRequest.getMetadata().entrySet()) {
                    String headerKey = "metadata-" + entry.getKey();
                    kafkaHeaders.add(new RecordHeader(headerKey, 
                        entry.getValue().getBytes(StandardCharsets.UTF_8)));
                }
            }
            
            kafkaHeaders.add(new RecordHeader("timestamp", 
                String.valueOf(System.currentTimeMillis()).getBytes(StandardCharsets.UTF_8)));
            kafkaHeaders.add(new RecordHeader("event-type", 
                eventRequest.getEventType().getBytes(StandardCharsets.UTF_8)));
            
            String messageValue = objectMapper.writeValueAsString(eventRequest.getPayload());
            
            ProducerRecord<String, String> producerRecord = new ProducerRecord<>(
                eventRequest.getTopic(),
                null,
                eventRequest.getKey(),
                messageValue,
                kafkaHeaders
            );
            
            RecordMetadata metadata = kafkaTemplate.send(producerRecord).get().getRecordMetadata();
            
            return new EventResponse(
                true,
                "Event published successfully",
                metadata.topic(),
                metadata.partition(),
                metadata.offset(),
                metadata.timestamp()
            );
            
        } catch (Exception e) {
            return new EventResponse(false, "Failed to publish event: " + e.getMessage());
        }
    }

    @PostMapping("/publish/batch")
    public BatchEventResponse publishBatchEvents(@RequestBody BatchEventRequest batchRequest,
                                                 @RequestHeader(value = "tracking-id", required = false) String trackingId,
                                                 @RequestHeader(value = "user-id", required = false) String userId) {
        
        List<EventResponse> responses = new ArrayList<>();
        
        for (EventRequest eventRequest : batchRequest.getEvents()) {
            EventResponse response = publishEvent(eventRequest, trackingId, userId, null);
            responses.add(response);
        }
        
        long successCount = responses.stream().filter(EventResponse::isSuccess).count();
        
        return new BatchEventResponse(
            successCount == responses.size(),
            successCount + " out of " + responses.size() + " events published successfully",
            responses
        );
    }
}

