@RestController
@RequestMapping("/api/events/custom")
class CustomHeaderEventProducerController {

    private final KafkaTemplate<String, String> kafkaTemplate;
    private final ObjectMapper objectMapper;

    public CustomHeaderEventProducerController(KafkaTemplate<String, String> kafkaTemplate, 
                                              ObjectMapper objectMapper) {
        this.kafkaTemplate = kafkaTemplate;
        this.objectMapper = objectMapper;
    }

    @PostMapping("/publish")
    public EventResponse publishEventWithCustomHeaders(
            @RequestBody Map<String, Object> requestBody,
            @RequestHeader Map<String, String> allHeaders) {
        
        try {
            String topic = (String) requestBody.getOrDefault("topic", "default-topic");
            String key = (String) requestBody.get("key");
            String eventType = (String) requestBody.getOrDefault("eventType", "custom-event");
            Object payload = requestBody.get("payload");
            
            List<Header> kafkaHeaders = new ArrayList<>();
            
            Set<String> standardHeaders = new HashSet<>(Arrays.asList(
                "host", "content-type", "content-length", "user-agent", "accept", 
                "accept-encoding", "connection", "cache-control"
            ));
            
            for (Map.Entry<String, String> header : allHeaders.entrySet()) {
                String headerKey = header.getKey().toLowerCase();
                if (!standardHeaders.contains(headerKey)) {
                    kafkaHeaders.add(new RecordHeader(header.getKey(), 
                        header.getValue().getBytes(StandardCharsets.UTF_8)));
                }
            }
            
            kafkaHeaders.add(new RecordHeader("event-type", 
                eventType.getBytes(StandardCharsets.UTF_8)));
            kafkaHeaders.add(new RecordHeader("timestamp", 
                String.valueOf(System.currentTimeMillis()).getBytes(StandardCharsets.UTF_8)));
            
            String messageValue = objectMapper.writeValueAsString(payload);
            
            ProducerRecord<String, String> producerRecord = new ProducerRecord<>(
                topic,
                null,
                key,
                messageValue,
                kafkaHeaders
            );
            
            RecordMetadata metadata = kafkaTemplate.send(producerRecord).get().getRecordMetadata();
            
            return new EventResponse(
                true,
                "Event published successfully with custom headers",
                metadata.topic(),
                metadata.partition(),
                metadata.offset(),
                metadata.timestamp()
            );
            
        } catch (Exception e) {
            return new EventResponse(false, "Failed to publish event: " + e.getMessage());
        }
    }
}